var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"고생 많으셨어요, 스완님. 이제 촬영도 거의 막바지에 이르렀네요.","JPN":"お疲れ様でした、スワンさん。あと少しで撮影が終わりそうですね。","ENG":"Great work, Miss Swan. We are almost done with the shoot.","TWN":"辛苦了，史旺。現在拍攝也快接近尾聲了。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"마지막까지 각본이 정말 흥미진진하던데요?","JPN":"脚本のラストシーンがどう撮られるか、今から楽しみです。","ENG":"The script was really thrilling until the end.","TWN":"直到最後劇本都非常引人入勝呢。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"시청자 반응도 아주 좋아요. 스폰서랑 감독님은 벌써 다음 시즌 이야기를 하는 거 있죠?","JPN":"視聴者の反応も上々です。それにスポンサーと監督が、もう次のシーズンについて話してましたよ。","ENG":"Even the viewers' reaction is great. The director and sponsor are already talking about making another season, did you know?","TWN":"贊助商的反應也非常好。已經在和導演討論下一季的事情了呢？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……다음 시즌?","JPN":"……次のシーズン？","ENG":"...Next season?","TWN":"……下一季？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요. 무슨 소리를 하는 지 모르겠군요.","JPN":"何を言ってるんですか？","ENG":"Well, I don't know anything about that.","TWN":"我聽不懂你在說什麼。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다음 시즌 같은 건 없습니다. 각본의 결말은 아주 오래전부터 정해져 있었으니까요.","JPN":"次のシーズンなんてありませんよ。脚本の結末は、ずっと昔から決まっていましたから。","ENG":"There is no next season. The ending of the script has been decided a long time ago.","TWN":"沒有下一季了。劇本的結局早在很久以前就已經定好了。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마지막은 주인공인 탐정이 숙적과 함께 죽음을 맞이하는 결말이에요.","JPN":"最後は主人公である探偵が宿敵とともに死を迎えるんです。","ENG":"It ends with the main character, the detective, dying with his nemesis.","TWN":"最後是偵探主角和宿敵一起迎接死亡的結局。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"네……?","JPN":"え……？","ENG":"What...?","TWN":"嗯……？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 말씀이세요?","JPN":"どういうことですか？","ENG":"What do you mean?","TWN":"你在說什麼啊？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"인기 주인공을 죽이겠다고요? 시청자들이 가만 안 있을 것 같은데……?","JPN":"人気のある主人公を殺すっていうんですか？　視聴者が黙っちゃいなさそうですけど……？","ENG":"You're going to kill off the main character? Our viewers won't like that...","TWN":"要抹殺掉人氣主角嗎？觀眾們可不會善罷甘休……？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그보다! 그럼, 스폰서와의 계약은 어쩌시게요?","JPN":"いや、それより！　じゃあ、スポンサーとの契約はどうするんですか？","ENG":"No, besides that! Then, what about the contract with the sponsor?","TWN":"不，比起這個！那和贊助商的合同怎麼辦？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 멋대로 결말을 내버리면, 저희에게 막대한 위약금을 요구할 텐데요……?","JPN":"そうやって勝手に結末を決めたら、私たちに莫大な違約金を要求してくるんじゃ……？","ENG":"If you end it like that, they're going to ask for a huge settlement.","TWN":"如果就這樣擅自結束的話，他們會向我們索要巨額違約金的……？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"감독이 멋대로 벌인 짓이군요.","JPN":"監督が勝手に決めたことですよね？","ENG":"So the director decided all this behind my back, I see.","TWN":"看來是導演的自作主張吧。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"상관없습니다. 제가 없는 자리에서 발생한 계약 사항 따위 관심 없으니까요.","JPN":"私には関係ありません。私がいないところで発生した契約事項なんて、興味ありませんから。","ENG":"No matter. I'm not interested in a contract that happened when I wasn't present.","TWN":"無所謂。我不在場時簽署的合同還輪不到我來操心。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가서 감독에게 전하세요.","JPN":"監督に伝えてください。","ENG":"Go tell this to the director.","TWN":"去告訴導演。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"차주에 촬영을 진행할 각본이 이 드라마의 마지막 에피소드입니다.","JPN":"来週に撮影する脚本が、このドラマの最後のエピソードですって。","ENG":"The script for next week's filming will be the last episode of the series.","TWN":"下周要拍攝的劇本是這部電視劇的最後一集。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 후, 저는 모든 작품 활동을 중단하고 휴식 기간을 가질 거예요.","JPN":"その後、私はすべての活動を中断して休止期間を持ちます。","ENG":"Afterward, I will stop all work and take a break.","TWN":"之後，我將暫停所有演藝活動，進入休息期。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"네에에……?","JPN":"えええっ……？","ENG":"Whaaaat...?","TWN":"……什麼？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"에피소드의 제목은…….","JPN":"エピソードのタイトルは……","ENG":"And the title of this last episode...","TWN":"這一集的標題是……"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요, <color=#ffd34c>마지막 사건</color>이 좋겠군요.","JPN":"そうですね、<color=#ffd34c>最後の事件</color>がいいですね。","ENG":"Yes, <color=#ffd34c>The Final Problem</color> should be appropriate.","TWN":"好吧，<color=#ffd34c>最後一案</color>，這個名字很不錯。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後","SCN":"几天后","DEU":"A few days later","FRA":"A few days later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>\\n건틀렛 리그 4강 경기 진행 중","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>\\nガントレットリーグ準決勝戦中","ENG":"[[","TWN":"管理局直轄市<color=#ffd34c>查雷德</color>\\n聖鎧聯賽四強賽進行中","SCN":"管理局直辖城市<color=#ffd34c>查雷德</color>\\n圣铠联赛四强赛进行中","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"제한 시간은 점점 다가오는데─!","JPN":"刻々と制限時間が迫っている中─！","ENG":"The clock is ticking–!","TWN":"時間就快到囉—！"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};